defmodule MyApp.Accounts do
  alias MyApp.Repo
  alias MyApp.Accounts.User

  def get_user_by_id_and_tenant(id, tenant_id) do
    Repo.get_by(User, id: id, tenant_id: tenant_id)
    |> case do
      nil -> {:error, :not_found}
      user -> {:ok, user}
